const e=JSON.parse('{"key":"v-7f20219d","path":"/posts/%E8%BE%93%E5%85%A5url%E5%88%B0%E9%A1%B5%E9%9D%A2%E5%B1%95%E7%A4%BA%E5%90%8E%E5%8F%91%E7%94%9F%E4%BB%80%E4%B9%88.html","title":"输入url到页面展示后发生什么，串联起计算机网络知识了","lang":"zh-CN","frontmatter":{"title":"输入url到页面展示后发生什么，串联起计算机网络知识了","isTimeLine":true,"date":"2025-06-08T00:00:00.000Z","category":["前端"],"tag":["性能优化","计算机网络"]},"headers":[{"level":3,"title":"浏览器搜索框按下回车后发生了什么？","slug":"浏览器搜索框按下回车后发生了什么","link":"#浏览器搜索框按下回车后发生了什么","children":[]},{"level":3,"title":"五层模型？","slug":"五层模型","link":"#五层模型","children":[]},{"level":3,"title":"DNS解析？","slug":"dns解析","link":"#dns解析","children":[]},{"level":3,"title":"UDP与TCP的区别是什么？","slug":"udp与tcp的区别是什么","link":"#udp与tcp的区别是什么","children":[]},{"level":3,"title":"TCP三次握手四次挥手？","slug":"tcp三次握手四次挥手","link":"#tcp三次握手四次挥手","children":[]},{"level":3,"title":"常见的请求方法？","slug":"常见的请求方法","link":"#常见的请求方法","children":[]},{"level":3,"title":"get与post的区别是什么？","slug":"get与post的区别是什么","link":"#get与post的区别是什么","children":[]},{"level":3,"title":"HTTP状态码？","slug":"http状态码","link":"#http状态码","children":[]},{"level":3,"title":"HTTP？","slug":"http","link":"#http","children":[]},{"level":3,"title":"HTTPS？","slug":"https","link":"#https","children":[]},{"level":3,"title":"HTTP与HTTPS区别？","slug":"http与https区别","link":"#http与https区别","children":[]},{"level":3,"title":"链接","slug":"链接","link":"#链接","children":[]}],"git":{"createdTime":1773252729000,"updatedTime":1773286516000,"contributors":[{"name":"liunal","email":"liunal","commits":2}]},"readingTime":{"minutes":12.03,"words":3609},"filePathRelative":"posts/输入url到页面展示后发生什么.md","localizedDate":"2025年6月8日","excerpt":"<h3> 浏览器搜索框按下回车后发生了什么？</h3>\\n<ol>\\n<li><code>解析URL：</code>输入url并回车后浏览器进程检查url，组装协议去构成完整的url，浏览器进程通过进程间通信（IPC）把url请求发送给网络进程。</li>\\n<li><code>缓存检查：</code>网络进程收到url请求后检查本地缓存是否有缓存，如果有则将该资源返回给浏览器进程。</li>\\n<li><code>网络进程向服务器发起网络请求：</code>① 进行DNS解析获取服务器的ip、端口；② 浏览器需要和服务器建立连接，进入TCP队列进行三次握手；③ HTTPS建立TLS连接；④ 向服务器发送HTTP请求（请求行、请求头、请求体）。</li>\\n<li><code>服务器处理请求并返回响应: </code>网络进程接收响应头和响应信息并解析响应内容。状态码内容 ① 如果是<code>301、302</code>那么就是数据重定向，从Location获取地址重新发起请求；② 如果是<code>304</code>那么就是使用本地缓存； ③ 如果是<code>200</code>，那么检测响应类型<code>Content-Type</code>,字节流类型那么提交给下载管理器进行下载；html则需要渲染页面，通知浏览器进程准备渲染进程。</li>\\n<li><code>数据传输完成：</code>TCP四次挥手断开连接。如果HTTP头部加上<code>Connection:Keep-Alive</code>，TCP就一直保持连接。保持TCP连接可以省下下次需要建立连接的时间，提示资源加载速度。</li>\\n<li><code>渲染进程接收数据：</code>渲染进程收到消息后，会和网络进程建立传输数据的“管道”，文档数据传输完成后，渲染进程会返回“确认提交”的消息给浏览器进程。</li>\\n<li><code>浏览器更新页面状态：</code>浏览器收到“确认提交”的消息后，会更新浏览器的页面状态，包括了安全状态、地址栏的 URL、前进后退的历史状态，并更新web页面，此时的web页面是空白页。</li>\\n<li><code>页面渲染：</code></li>\\n</ol>"}');export{e as data};
